import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";
import "./PriceAnalytics.css";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

const API_BASE = "http://localhost:7000/api";

const PriceAnalytics = () => {
  const [loading, setLoading] = useState(true);
  const [productList, setProductList] = useState([]);
  const [categoryList, setCategoryList] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [chartData, setChartData] = useState(null);

  // Fetch product & category dropdown data
  useEffect(() => {
    const fetchDropdowns = async () => {
      try {
        const [products, categories] = await Promise.all([
          axios.get(`${API_BASE}/prices`),
          axios.get(`${API_BASE}/categories`),
        ]);
        setProductList(products.data.data || []);
        setCategoryList(categories.data.categories || []);
      } catch (err) {
        console.error("Dropdown fetch error:", err);
      }
    };
    fetchDropdowns();
  }, []);

  // Fetch data for graph
  const fetchChart = async () => {
    setLoading(true);
    try {
      let query = "";
      if (selectedProduct) query += `&product=${selectedProduct}`;
      if (selectedCategory) query += `&category=${selectedCategory}`;
      if (startDate && endDate) query += `&start=${startDate}&end=${endDate}`;

      const res = await axios.get(`${API_BASE}/price-report/range?${query}`);
      const data = res.data.data || [];

      if (data.length === 0) {
        setChartData(null);
        setLoading(false);
        return;
      }

      // Prepare graph data
      const labels = data.map((item) => item.name);
      const basePrices = data.map((item) => item.basePrice);
      const differences = data.map((item) => item.difference || 0);

      setChartData({
        labels,
        datasets: [
          {
            label: "Base Price (₹)",
            data: basePrices,
            backgroundColor: "rgba(0, 123, 255, 0.6)",
            borderRadius: 8,
          },
          {
            label: "Difference (₹)",
            data: differences,
            backgroundColor: "rgba(255, 193, 7, 0.6)",
            borderRadius: 8,
          },
        ],
      });
    } catch (err) {
      console.error("Chart data fetch error:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchChart();
  }, [selectedProduct, selectedCategory, startDate, endDate]);

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📊 Price Analytics Dashboard</h2>
      <p className="analytics-subtitle">
        Compare product and category prices over custom date ranges
      </p>

      {/* 🔹 Filters */}
      <div className="filter-section">
        <div className="filter-group">
          <label>🧃 Product:</label>
          <select
            value={selectedProduct}
            onChange={(e) => setSelectedProduct(e.target.value)}
          >
            <option value="">All Products</option>
            {productList.map((p) => (
              <option key={p._id} value={p.name}>
                {p.name}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-group">
          <label>🗂️ Category:</label>
          <select
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            <option value="">All Categories</option>
            {categoryList.map((c) => (
              <option key={c._id} value={c.name}>
                {c.name}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-group">
          <label>📅 From:</label>
          <input
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
          />
        </div>

        <div className="filter-group">
          <label>➡️ To:</label>
          <input
            type="date"
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
          />
        </div>

        <button className="btn refresh" onClick={fetchChart}>
          🔄 Apply Range
        </button>
      </div>

      {/* Chart */}
      <div className="chart-wrapper">
        {loading ? (
          <div className="loading">Loading chart...</div>
        ) : chartData ? (
          <Bar
            data={chartData}
            options={{
              responsive: true,
              maintainAspectRatio: false,
              plugins: {
                legend: { position: "bottom" },
                tooltip: {
                  callbacks: {
                    label: (context) =>
                      `${context.dataset.label}: ₹${context.parsed.y}`,
                  },
                },
              },
              scales: {
                x: {
                  ticks: { color: "#333" },
                  title: { display: true, text: "Products", color: "#444" },
                },
                y: {
                  beginAtZero: true,
                  title: {
                    display: true,
                    text: "Price (₹)",
                    color: "#444",
                  },
                },
              },
            }}
          />
        ) : (
          <div className="no-data">No data found for selected range.</div>
        )}
      </div>
    </div>
  );
};

export default PriceAnalytics;
